import React from 'react'
import { Button } from '/src/components'

export const CompetencyToggleButton = ({ isToggled, className, ...restProps }) => (
  <Button
    variant={isToggled ? 'contained' : 'outline'}
    size="sm"
    className={!isToggled ? `rounded-full border-indigo-800 text-indigo-800` : `rounded-full bg-indigo-900`}
    {...restProps}
  />
)
