import React, { useMemo } from 'react'
import { format, formatISO, parseISO, nextMonday } from 'date-fns'
import { TW_COLOR_CYCLE } from '/src/color'
import classNames from 'classnames'

const WEEK_WIDTH = 600
const getTasksByDate = (projects) => {
  let tasksByDate = {}
  for (const project of projects) {
    if (!project.tasks) {
      continue
    }
    const projectTasks = [...project.tasks]
    projectTasks.sort(({ estimate: estimateA = 1 }, { estimate: estimateB = 1 }) => estimateB - estimateA)
    for (const task of projectTasks ?? []) {
      tasksByDate[task.startDate] = tasksByDate[task.startDate] || []
      tasksByDate[task.startDate].push({ project, task })
    }
  }
  return tasksByDate
}

const getProjectsPriorityMap = (projects) =>
  Object.fromEntries(Object.entries(projects).map(({ id }, index) => [id, index]))

const compareTaskByDateEntry = ([dateA], [dateB]) => {
  if (dateA === dateB) {
    return 0
  }
  return dateA > dateB ? 1 : -1
}

const mergeTasks = (projectPriorityMap, tasksA, tasksB) => {
  const result = tasksA.concat(tasksB)
  result.sort(
    ({ project: projectA }, { project: projectB }) => projectPriorityMap[projectA.id] - projectPriorityMap[projectB.id]
  )
  return result
}

const getCapacityDelta = (memberCapacity, taskCapacity = 1) => ({
  taskEstimateRemaining: Math.max(0, taskCapacity - memberCapacity),
  capacity: Math.max(0, memberCapacity - taskCapacity),
})

const getInitWeeklyWork = (teamMembers, previousWeek = {}) =>
  teamMembers.map((member) => {
    const { taskEstimateRemaining = 0, tasks = [] } = previousWeek[member.id] ?? {}

    const lastTask = tasks[tasks.length - 1]

    return {
      memberId: member.id,
      tasks: taskEstimateRemaining > 0 && lastTask ? [lastTask] : [],
      ...getCapacityDelta((member.capacity ?? 3) * 5, taskEstimateRemaining),
    }
  })

const getWeeklyTaskAssignment = (teamMembers, tasksTodo, previousWeek = {}, capacityOverrides = null) => {
  let weeklyWork = getInitWeeklyWork(teamMembers, previousWeek)
  weeklyWork.sort(({ capacity: capacityA }, { capacity: capacityB }) => capacityB - capacityA)

  let nMembersWithCapacity = weeklyWork.filter(({ capacity }) => capacity).length

  let remainingTodos = []
  let tasksTodoCounter = 0
  while (nMembersWithCapacity && tasksTodoCounter < tasksTodo.length) {
    for (const memberWork of weeklyWork) {
      if (tasksTodoCounter >= tasksTodo.length) {
        break
      }

      if (memberWork.capacity === 0) {
        continue
      }

      const taskTodo = tasksTodo[tasksTodoCounter++]
      memberWork.tasks.push(taskTodo)

      Object.assign(memberWork, getCapacityDelta(memberWork.capacity, taskTodo.task.estimate))
      if (memberWork.capacity === 0) {
        nMembersWithCapacity--
      }
    }
  }
  return [
    Object.fromEntries(weeklyWork.map((memberWork) => [memberWork.memberId, memberWork])),
    remainingTodos.concat(tasksTodo.slice(tasksTodoCounter)),
  ]
}

export const GanttChart = ({ projects, teamMembers }) => {
  const [weeklyTasks, projectPriorityMap] = useMemo(() => {
    let tasksByDate = getTasksByDate(projects)
    let weeklyTasks = Object.entries(tasksByDate)
    weeklyTasks.sort(compareTaskByDateEntry)
    return [weeklyTasks, getProjectsPriorityMap(projects)]
  }, [projects])

  const maxWeeklyCapacity = useMemo(() => 5 * Math.max(...teamMembers.map(({ capacity }) => capacity)), [teamMembers])

  const ganttData = useMemo(() => {
    let weeklyTasksIter = 0
    let tasksTodo = []
    let ganttData = []
    let week = null
    while (tasksTodo.length || weeklyTasksIter < weeklyTasks.length) {
      let [pendingTasksWeek, pendingTasks] = weeklyTasks[weeklyTasksIter]
      week = week === null ? parseISO(pendingTasksWeek) : nextMonday(week)
      if (formatISO(week, { representation: 'date' }) === pendingTasksWeek) {
        weeklyTasksIter++
        tasksTodo = mergeTasks(projectPriorityMap, tasksTodo, pendingTasks)
      }
      let weeklyWork
      ;[weeklyWork, tasksTodo] = getWeeklyTaskAssignment(teamMembers, tasksTodo, ganttData[ganttData.length - 1]?.[1])
      ganttData.push([week, weeklyWork])
    }
    return ganttData
  }, [weeklyTasks, teamMembers])

  console.log({ teamMembers, ganttData })
  return (
    <>
      <div className="w-full flex">
        <div className="flex flex-col gap-y-4">
          <div className="text-center py-4">
            <div className="invisible">
              <div className="font-bold text-sm uppercase ">0</div>
              <div className="">0</div>
            </div>
          </div>
          {teamMembers.map((member) => (
            <div key={member.id} className="px-4 relative whitespace-nowrap">
              {member.name}
              <div
                className="flex absolute inset-y-0 left-full bg-neutral-50"
                style={{ minWidth: WEEK_WIDTH * ganttData.length }}
              >
                {ganttData.map(([_, assignedTasks], weeklyWorkIndex) => {
                  const memberWork = assignedTasks[member.id]
                  return (
                    <div key={weeklyWorkIndex} className="flex">
                      {memberWork.tasks.length ? (
                        memberWork.tasks.map(({ project, task }, index) => {
                          const projectColor = TW_COLOR_CYCLE[project.id % TW_COLOR_CYCLE.length].join(' ')
                          const taskEstimateRemaining =
                            ganttData[weeklyWorkIndex - 1]?.[1]?.[member.id]?.taskEstimateRemaining ?? 0
                          const isSpilloverTask = index === 0 && taskEstimateRemaining > 0
                          const taskName = !isSpilloverTask && (task.name ?? `Task ID ${task.id}`)
                          return (
                            <div
                              key={index}
                              style={{
                                width:
                                  (WEEK_WIDTH *
                                    Math.min(
                                      (member.capacity ?? 3) * 5,
                                      isSpilloverTask ? taskEstimateRemaining : task.estimate
                                    )) /
                                  maxWeeklyCapacity,
                                marginRight:
                                  index === memberWork.tasks.length - 1
                                    ? (WEEK_WIDTH * memberWork.capacity) / maxWeeklyCapacity
                                    : 0,
                              }}
                              className={classNames('px-2 h-full flex items-center', projectColor, {
                                'rounded-l-lg': !isSpilloverTask,
                                'rounded-r-lg':
                                  index !== memberWork.tasks.length - 1 || memberWork.taskEstimateRemaining === 0,
                              })}
                              title={taskName ? taskName : undefined}
                            >
                              <div className="w-full overflow-hidden whitespace-nowrap text-ellipsis text-sm">
                                {taskName}
                              </div>
                            </div>
                          )
                        })
                      ) : (
                        <div style={{ marginRight: WEEK_WIDTH }} />
                      )}
                    </div>
                  )
                })}
              </div>
            </div>
          ))}
        </div>
        {ganttData.map(([weekDate], i) => (
          <div key={i} className="text-center py-4 -mt-[2px]">
            <div style={{ width: WEEK_WIDTH }} className="font-bold text-sm uppercase">
              Week {i + 1}
            </div>
            <div style={{ width: WEEK_WIDTH }}>{format(weekDate, 'PP')}</div>
          </div>
        ))}
      </div>
    </>
  )
}
